import{_ as e,a as t,b as r,c as o}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as i,c as n,a2 as u}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Backup redundante e troca da origem de leitura","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/redundant-backup-and-read-source.md","filePath":"pt-BR/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),c={name:"pt-BR/Other/redundant-backup-and-read-source.md"};function p(s,a,l,m,h,b){return i(),n("div",null,[...a[0]||(a[0]=[u('<h1 id="backup-redundante-e-troca-da-origem-de-leitura" tabindex="-1">Backup redundante e troca da origem de leitura <a class="header-anchor" href="#backup-redundante-e-troca-da-origem-de-leitura" aria-label="Permalink to &quot;Backup redundante e troca da origem de leitura&quot;">​</a></h1><p>O backup redundante salva uma cópia extra de arquivos que já foram enviados.</p><p>Para visitantes, o arquivo principal e a cópia parecem iguais. A diferença está no canal de armazenamento usado para ler o arquivo.</p><h2 id="o-que-da-para-fazer" tabindex="-1">O que dá para fazer <a class="header-anchor" href="#o-que-da-para-fazer" aria-label="Permalink to &quot;O que dá para fazer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Recurso</th><th>Descrição</th></tr></thead><tbody><tr><td>Salvar uma cópia extra</td><td>Copia o arquivo para outro canal e reduz dependência de um único armazenamento</td></tr><tr><td>Trocar origem de leitura</td><td>Alterna entre canal principal e canal de backup</td></tr><tr><td>Backup de arquivo único</td><td>Cria cópia a partir dos detalhes de um arquivo</td></tr><tr><td>Backup em lote</td><td>Seleciona vários arquivos no painel e copia de uma vez</td></tr><tr><td>Backup global</td><td>Completa backups por pasta em Outras configurações</td></tr></tbody></table><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações -&gt; Backup redundante</span></span></code></pre></div><p><img src="'+e+'" alt="Backup redundante" loading="lazy"></p><p>Aqui você pode completar backups para uma pasta específica ou para todos os arquivos. O canal de backup pode ser escolhido manualmente ou ficar em modo automático para o ImgBed selecionar um canal adequado.</p><h2 id="backup-pelo-detalhe-do-arquivo" tabindex="-1">Backup pelo detalhe do arquivo <a class="header-anchor" href="#backup-pelo-detalhe-do-arquivo" aria-label="Permalink to &quot;Backup pelo detalhe do arquivo&quot;">​</a></h2><p>No painel, abra os detalhes de um arquivo e use a ação de backup.</p><p><img src="'+t+'" alt="Backup no detalhe" loading="lazy"></p><p>Esse acesso é útil para proteger arquivos importantes de forma pontual. Após um backup bem-sucedido, os detalhes mostram as origens de leitura disponíveis.</p><h2 id="backup-por-selecao" tabindex="-1">Backup por seleção <a class="header-anchor" href="#backup-por-selecao" aria-label="Permalink to &quot;Backup por seleção&quot;">​</a></h2><p>No painel, selecione vários arquivos e execute o backup em lote.</p><p><img src="'+r+'" alt="Backup em lote" loading="lazy"></p><p>Backup pelo detalhe, backup por seleção e backup redundante em Outras configurações usam a mesma lógica; muda apenas o ponto de entrada.</p><h2 id="trocar-origem-de-leitura" tabindex="-1">Trocar origem de leitura <a class="header-anchor" href="#trocar-origem-de-leitura" aria-label="Permalink to &quot;Trocar origem de leitura&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Origem</th><th>Descrição</th></tr></thead><tbody><tr><td>Canal principal</td><td>Lê a partir do canal usado no upload original</td></tr><tr><td>Canal de backup</td><td>Lê a partir do canal onde a cópia foi salva</td></tr></tbody></table><p><img src="'+o+'" alt="Troca de origem" loading="lazy"></p><p>Após a troca, imagens, vídeos e links de download continuam funcionando normalmente usando a origem escolhida.</p><h2 id="casos-ignorados" tabindex="-1">Casos ignorados <a class="header-anchor" href="#casos-ignorados" aria-label="Permalink to &quot;Casos ignorados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caso</th><th>Motivo</th></tr></thead><tbody><tr><td>Já tem backup</td><td>Evita duplicar espaço sem necessidade</td></tr><tr><td>Canal principal igual ao canal de backup</td><td>Copiar para o mesmo canal não traz redundância</td></tr><tr><td>Sem canal disponível</td><td>Não foi encontrado outro canal adequado</td></tr></tbody></table><h2 id="ao-excluir-arquivos" tabindex="-1">Ao excluir arquivos <a class="header-anchor" href="#ao-excluir-arquivos" aria-label="Permalink to &quot;Ao excluir arquivos&quot;">​</a></h2><p>Ao excluir um arquivo, o ImgBed remove tanto o arquivo principal quanto a cópia de backup.</p>',25)])])}const v=d(c,[["render",p]]);export{q as __pageData,v as default};
